from .core import EventBus


class Subscriber:
    """Manages subscriptions to an EventBus."""

    def __init__(self, bus: EventBus, event_handler=None):
        if not isinstance(bus, EventBus):
            raise TypeError(f"Expected EventBus, got {type(bus).__name__}")
        self._bus = bus
        self.event_handler = event_handler
        self.event_name = "subscriber"

    def listen(self, event_type):
        """Subscribe the event_handler to the given type."""
        if self.event_handler is not None:
            self._bus.subscribe(event_type, self.event_handler)

    def push(self, event):
        """Push an event through the bus."""
        self._bus.emit(event)

