from .core import EventBus


class Publisher:
    """Publishes events to a bus with tracking."""

    def __init__(self, bus: EventBus):
        if not isinstance(bus, EventBus):
            raise TypeError(f"Expected EventBus, got {type(bus).__name__}")
        self._bus = bus
        self.event_count = 0
        self.event_data = {}

    def publish(self, event):
        """Publish an event and track it."""
        self.event_count += 1
        self.event_data[self.event_count] = event
        self._bus.emit(event)
        return self.event_count

