from .core import EventBus
from .errors import EventError


class Router:
    """Routes events across multiple buses by event type."""

    def __init__(self):
        self._routes = {}

    def add_route(self, event_type, bus: EventBus):
        """Map an event type to a specific bus."""
        if not isinstance(bus, EventBus):
            raise TypeError(f"Expected EventBus, got {type(bus).__name__}")
        self._routes[event_type] = bus

    def route(self, event):
        """Route an event to the correct bus."""
        event_type = event.get("type", "unknown")
        event_name = event.get("name", "")
        bus = self._routes.get(event_type)
        if bus is None:
            raise EventError(event_type, event_name, "no route")
        bus.emit(event)
        return event_type

    def list_routes(self):
        return list(self._routes.keys())

