from .core import EventBus


class FilteredBus(EventBus):
    """EventBus subclass that filters events by predicate."""

    def __init__(self, name="filtered", predicate=None):
        super().__init__(name)
        self.predicate = predicate or (lambda event: True)

    def emit(self, event):
        """Only emit if the event passes the predicate."""
        event_type = event.get("type", "unknown")
        if self.predicate(event):
            super().emit(event)

