class EventQueue:
    """Queues events for batch processing."""

    def __init__(self, bus):
        self._bus = bus
        self._pending = []
        self.event_data = {}

    def enqueue(self, event, event_id=None):
        """Add an event to the queue with optional tracking ID."""
        entry = {"event_id": event_id or len(self._pending), "payload": event}
        self._pending.append(entry)

    def flush(self):
        """Emit all queued events."""
        results = []
        for entry in self._pending:
            event = entry["payload"]
            self._bus.emit(event)
            results.append(entry["event_id"])
        self.event_data = {"flushed": len(results)}
        self._pending.clear()
        return results

