from .core import EventBus


class Monitor:
    """Monitors EventBus with metrics tracking."""

    def __init__(self, bus: EventBus):
        if not isinstance(bus, EventBus):
            raise TypeError(f"Expected EventBus, got {type(bus).__name__}")
        self._bus = bus
        self.event_id = f"mon-{bus.name}"
        self.event_count = 0

    def tracked_emit(self, event):
        """Emit an event while tracking metrics."""
        self.event_count += 1
        self._bus.emit(event)
        return {"event_id": self.event_id, "count": self.event_count}

