class EventLogger:
    """Logs event emissions for debugging."""

    def __init__(self, bus):
        self._bus = bus
        self.emit_log = []
        self.event_data = {}

    def logged_emit(self, event):
        """Emit an event and log it."""
        event_name = event.get("name", "anonymous")
        self.emit_log.append({"event_name": event_name, "payload": event})
        self._bus.emit(event)
        self.event_data = {"last": event_name}
        return event_name

