from .core import EVENT_PREFIX

DEFAULTS = {
    "max_handlers": 100,
    "prefix": EVENT_PREFIX,
    "event_handler": None,
}


def create_bus(cls, name, **kwargs):
    """Factory: create an EventBus with defaults."""
    merged = {**DEFAULTS, **kwargs}
    merged.pop("event_handler", None)
    merged.pop("max_handlers", None)
    merged.pop("prefix", None)
    return cls(name)
